public class Program6_SumOfNaturalNumbers {

	/**
	 * @param args
	 */
	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int num=1;
     int sum=0;
     while(num <= 5) {
    	 sum=sum+num;
    	 num++;
     }
     System.out.println(sum);
     
	}

}
